SELECT * FROM(SELECT DISTINCT PGM_YR,ADM_ST_FSA_CD,ADM_CNTY_FSA_CD,TR_NBR,OFR_SCNR_NM,SGNP_NBR,SGNP_TYPE_DESC,SGNP_STYPE_DESC,SGNP_STYPE_AGR_NM,SOIL_GRP_NM,WT_AVG_SOIL_RNT_AMT,PRAC_MNT_RT,MAX_PYMT_RT,CALC_WTR_WT_ENVR_IDX,CALC_WIND_WT_ENVR_IDX,CALC_CLMT_WT_IDX,CALC_RKLS_WT_NBR,CALC_SOIL_LCH_WT_IDX,CALC_LONG_LEAF_NBR,CALC_WESL_NBR,CNSV_CTR_SEQ_NBR,CNSV_CTR_SFX_CD,OFR_SCNR_ID,DATA_STAT_CD,CRE_DT,LAST_CHG_DT,LAST_CHG_USER_NM,-- op,ROW_NUMBER() over ( partition by SOIL_GRP_NM,OFR_SCNR_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt44orent.SOIL_GRP_NM SOIL_GRP_NM,ewt44orent.WT_SOIL_RNT_AMT WT_AVG_SOIL_RNT_AMT,ewt44orent.PRAC_MNT_RT PRAC_MNT_RT,ewt44orent.MAX_PYMT_RT MAX_PYMT_RT,ewt44orent.CALC_WTR_WT_IDX CALC_WTR_WT_ENVR_IDX,ewt44orent.CALC_WIND_WT_IDX CALC_WIND_WT_ENVR_IDX,ewt44orent.CALC_CLMT_WT_IDX CALC_CLMT_WT_IDX,ewt44orent.CALC_RKLS_WT_NBR CALC_RKLS_WT_NBR,ewt44orent.CALC_LCH_WT_IDX CALC_SOIL_LCH_WT_IDX,ewt44orent.CALC_LONG_LEAF_NBR CALC_LONG_LEAF_NBR,ewt44orent.CALC_WESL_NBR CALC_WESL_NBR,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,ewt44orent.OFR_SCNR_ID OFR_SCNR_ID,ewt44orent.DATA_STAT_CD DATA_STAT_CD,ewt44orent.CRE_DT CRE_DT,ewt44orent.LAST_CHG_DT LAST_CHG_DT,ewt44orent.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT44ORENT LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT44ORENT.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt44orent.SOIL_GRP_NM SOIL_GRP_NM,ewt44orent.WT_SOIL_RNT_AMT WT_AVG_SOIL_RNT_AMT,ewt44orent.PRAC_MNT_RT PRAC_MNT_RT,ewt44orent.MAX_PYMT_RT MAX_PYMT_RT,ewt44orent.CALC_WTR_WT_IDX CALC_WTR_WT_ENVR_IDX,ewt44orent.CALC_WIND_WT_IDX CALC_WIND_WT_ENVR_IDX,ewt44orent.CALC_CLMT_WT_IDX CALC_CLMT_WT_IDX,ewt44orent.CALC_RKLS_WT_NBR CALC_RKLS_WT_NBR,ewt44orent.CALC_LCH_WT_IDX CALC_SOIL_LCH_WT_IDX,ewt44orent.CALC_LONG_LEAF_NBR CALC_LONG_LEAF_NBR,ewt44orent.CALC_WESL_NBR CALC_WESL_NBR,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,ewt44orent.OFR_SCNR_ID OFR_SCNR_ID,ewt44orent.DATA_STAT_CD DATA_STAT_CD,ewt44orent.CRE_DT CRE_DT,ewt44orent.LAST_CHG_DT LAST_CHG_DT,ewt44orent.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT40OFRSC JOIN "fsa-prod-cnsv".EWT44ORENT ON (EWT40OFRSC.OFR_SCNR_ID = ewt44orent.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)-- WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt44orent.SOIL_GRP_NM SOIL_GRP_NM,ewt44orent.WT_SOIL_RNT_AMT WT_AVG_SOIL_RNT_AMT,ewt44orent.PRAC_MNT_RT PRAC_MNT_RT,ewt44orent.MAX_PYMT_RT MAX_PYMT_RT,ewt44orent.CALC_WTR_WT_IDX CALC_WTR_WT_ENVR_IDX,ewt44orent.CALC_WIND_WT_IDX CALC_WIND_WT_ENVR_IDX,ewt44orent.CALC_CLMT_WT_IDX CALC_CLMT_WT_IDX,ewt44orent.CALC_RKLS_WT_NBR CALC_RKLS_WT_NBR,ewt44orent.CALC_LCH_WT_IDX CALC_SOIL_LCH_WT_IDX,ewt44orent.CALC_LONG_LEAF_NBR CALC_LONG_LEAF_NBR,ewt44orent.CALC_WESL_NBR CALC_WESL_NBR,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,ewt44orent.OFR_SCNR_ID OFR_SCNR_ID,ewt44orent.DATA_STAT_CD DATA_STAT_CD,ewt44orent.CRE_DT CRE_DT,ewt44orent.LAST_CHG_DT LAST_CHG_DT,ewt44orent.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,3 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT14SGNP LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT14SGNP.SGNP_ID = EWT40OFRSC.SGNP_ID) JOIN "fsa-prod-cnsv".EWT44ORENT ON (EWT40OFRSC.OFR_SCNR_ID = EWT44ORENT.OFR_SCNR_ID)--WHERE __CDC_OPERATION <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND (
 (COALESCE(CAST(CRE_DT AS DATE), DATE '1900-01-01') <= CAST('2025-12-01' AS DATE))
    AND
    (COALESCE(CAST(LAST_CHG_DT AS DATE), DATE '1900-01-01') <= CAST('2025-12-31' AS DATE))
)
UNIONSELECT DISTINCTNULL PGM_YR,NULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL TR_NBR,NULL OFR_SCNR_NM,NULL SGNP_NBR,NULL SGNP_TYPE_DESC,NULL SGNP_STYPE_DESC,NULL SGNP_STYPE_AGR_NM,ewt44orent.SOIL_GRP_NM SOIL_GRP_NM,ewt44orent.WT_SOIL_RNT_AMT WT_AVG_SOIL_RNT_AMT,ewt44orent.PRAC_MNT_RT PRAC_MNT_RT,ewt44orent.MAX_PYMT_RT MAX_PYMT_RT,ewt44orent.CALC_WTR_WT_IDX CALC_WTR_WT_ENVR_IDX,ewt44orent.CALC_WIND_WT_IDX CALC_WIND_WT_ENVR_IDX,ewt44orent.CALC_CLMT_WT_IDX CALC_CLMT_WT_IDX,ewt44orent.CALC_RKLS_WT_NBR CALC_RKLS_WT_NBR,ewt44orent.CALC_LCH_WT_IDX CALC_SOIL_LCH_WT_IDX,ewt44orent.CALC_LONG_LEAF_NBR CALC_LONG_LEAF_NBR,ewt44orent.CALC_WESL_NBR CALC_WESL_NBR,NULL CNSV_CTR_SEQ_NBR,NULL CNSV_CTR_SFX_CD,ewt44orent.OFR_SCNR_ID OFR_SCNR_ID,ewt44orent.DATA_STAT_CD DATA_STAT_CD,ewt44orent.CRE_DT CRE_DT,ewt44orent.LAST_CHG_DT LAST_CHG_DT,ewt44orent.LAST_CHG_USER_NM LAST_CHG_USER_NM,--'D' CDC_OPER_CD,1 AS row_num_partFROM "fsa-prod-cnsv".ewt44orent